-- ── AMT ──────────────────────────────────────────────────────
('AMT', 'Hardballer', '.45 ACP', 'Pistol', 'Single-Action', 7, 1977, true, 'United States', 'All-stainless steel long-slide 1911 in .45 ACP. Made famous as the Terminator''s weapon in the 1984 film.', 400, 42.0, 8.5, false, false, ARRAY['Hardballer Longslide (7" barrel)'], 'Discontinued', 'AMT Hardballer', ARRAY['.45 ACP'], ARRAY['hardballer', 'amt 1911'], 'Modern', 'Single-Action', ARRAY['carry', 'collector'], 'Arnold Schwarzenegger''s T-800 used the Hardballer Longslide in The Terminator — making it one of the most recognizable pistols in cinema history.', 'United States', true, 'Original AMT examples command collector premiums; later Galena/IAI versions are less desirable.'),

('AMT', 'Backup', '.380 ACP', 'Pistol', 'DA/SA', 5, 1976, true, 'United States', 'Compact all-stainless backup pistol in .380 ACP with a smooth double-action trigger. One of the earliest production stainless pocket pistols.', 300, 18.0, 5.0, false, false, ARRAY['Backup .45 ACP', 'Backup .38 Super', 'Backup .357 SIG'], 'Discontinued', 'AMT Backup', ARRAY['.380 ACP', '.45 ACP'], ARRAY['amt backup', 'backup 380'], 'Modern', 'DA/SA', ARRAY['carry'], NULL, 'United States', false, NULL),

('AMT', 'Automag II', '.22 Magnum', 'Pistol', 'Semi-Auto', 9, 1987, true, 'United States', 'Stainless semi-automatic pistol chambered in .22 Winchester Magnum Rimfire — one of the few production pistols ever offered in this caliber.', 350, 24.0, 6.0, false, false, ARRAY['Automag III (.30 Carbine)', 'Automag IV (.45 Win Mag)'], 'Discontinued', 'AMT Automag', ARRAY['.22 Magnum'], ARRAY['automag ii', 'amt automag 22 mag'], 'Modern', 'Single-Action', ARRAY['hunting', 'collector'], 'The .22 Magnum semi-auto pistol is an extremely niche product category. The Automag II was one of only a handful of production pistols ever offered in this caliber.', 'United States', false, NULL),

-- ── AMERICAN DERRINGER ────────────────────────────────────────
('American Derringer', 'Model 1', '.38 Special', 'Pistol', 'Single-Action', 2, 1980, false, 'United States', 'Over-under double-barrel derringer available in over 50 calibers from .22 LR to .45-70 Government. The most versatile derringer line ever produced.', 320, 15.5, 4.8, false, false, ARRAY['Model 1 in .45 Colt', 'Model 1 in .45-70', 'Model 1 in .44 Magnum'], 'Active', 'American Derringer Model 1', ARRAY['.38 Special', '.357 Magnum', '.45 Colt', '.45-70'], ARRAY['model 1 derringer', 'adc model 1'], 'Modern', 'Single-Action', ARRAY['carry', 'collector'], 'American Derringer offers the Model 1 in more calibers than virtually any other production handgun, including .45-70 Government.', 'United States', false, NULL),

('American Derringer', 'Lady Derringer', '.38 Special', 'Pistol', 'Single-Action', 2, 1985, false, 'United States', 'Engraved over-under derringer with rosewood or mother-of-pearl grips, marketed as a refined concealed carry option for women. Same mechanism as the Model 1.', 395, 15.5, 4.8, false, false, NULL, 'Active', 'American Derringer Lady', ARRAY['.38 Special', '.32 H&R Mag'], ARRAY['lady derringer', 'adc lady'], 'Modern', 'Single-Action', ARRAY['carry', 'collector'], NULL, 'United States', false, NULL),

('American Derringer', 'Model 4', '.357 Magnum', 'Pistol', 'Single-Action', 2, 1985, false, 'United States', 'Larger over-under derringer with a longer 4.1" barrel, offering better ballistics with the .357 Magnum and .45-70 Government in a more manageable platform than the Model 1.', 425, 16.5, 6.0, false, false, ARRAY['Model 4 in .45-70', 'Model 4 Alaskan Survival'], 'Active', 'American Derringer Model 4', ARRAY['.357 Magnum', '.45-70'], ARRAY['model 4 derringer'], 'Modern', 'Single-Action', ARRAY['carry', 'hunting', 'collector'], NULL, 'United States', false, NULL),

