('Anderson Manufacturing', 'AM-10', '.308 Winchester', 'Rifle', 'Semi-Auto', 20, 2014, false, 'United States', 'AR-10 platform semi-automatic rifle in .308 Winchester/7.62 NATO from Anderson Manufacturing. Uses DPMS-pattern lower.', 699, 152.0, 38.0, false, false, ARRAY['AM-10 Hunter', 'AM-10 Pistol'], 'Active', 'Anderson AM-10', ARRAY['.308 Win', '7.62 NATO'], ARRAY['am10', 'anderson 308'], 'Modern', 'Single-Action', ARRAY['hunting', 'sport'], NULL, 'United States', false, NULL),

