-- ── ANSCHUTZ ─────────────────────────────────────────────────
('Anschutz', '1710', '.22 LR', 'Rifle', 'Bolt-Action', 5, 1985, false, 'Germany', 'Anschutz 1710 is a precision .22 LR bolt-action sporting rifle offering competition-grade accuracy in a hunting-weight stock. Used by target shooters and benchrest competitors worldwide.', 1299, 87.0, 40.9, false, false, ARRAY['1710 D HB', '1710 Classic', '1710 D Classic'], 'Active', 'Anschutz 1700', ARRAY['.22 LR'], ARRAY['1710', 'anschutz 1710'], 'Modern', 'Single-Action', ARRAY['competition', 'hunting'], NULL, 'Germany', false, NULL),

('Anschutz', '1416', '.22 LR', 'Rifle', 'Bolt-Action', 5, 1990, false, 'Germany', 'Compact .22 LR bolt-action with classic European styling and the precision Anschutz 1416 action. Popular hunting and plinking rifle in Europe.', 899, 74.0, 39.0, false, false, ARRAY['1416 Classic', '1416 D HB'], 'Active', 'Anschutz 1400', ARRAY['.22 LR'], ARRAY['1416', 'anschutz 1416'], 'Modern', 'Single-Action', ARRAY['hunting', 'sport'], NULL, 'Germany', false, NULL),

('Anschutz', '1907', '.22 LR', 'Rifle', 'Bolt-Action', 5, 1957, false, 'Germany', 'Olympic-grade smallbore target rifle used in 50m prone and 3-position disciplines. The benchmark for .22 LR competition accuracy for over 60 years.', 2800, 122.0, 44.5, false, false, ARRAY['1907 in Precise', '1907 Club', '1913 Super Match'], 'Active', 'Anschutz 1900', ARRAY['.22 LR'], ARRAY['1907', 'anschutz 1907', 'anschutz match'], 'Cold War', 'Single-Action', ARRAY['competition'], 'Anschutz 1907 and 1913 rifles have won more Olympic and World Championship medals in smallbore shooting than any other rifle platform.', 'Germany', false, NULL),

-- ── ARMALITE ─────────────────────────────────────────────────
('Armalite', 'AR-10', '7.62 NATO', 'Rifle', 'Semi-Auto', 20, 1956, false, 'United States', 'The original AR-10, designed by Eugene Stoner and Armalite in 1956 — the direct ancestor of the M16. The modern Armalite AR-10 is a semi-auto .308 based on the original design. Lighter than contemporary .308 semi-autos at the time of its introduction.', 1499, 152.0, 40.5, false, false, ARRAY['AR-10 A4', 'AR-10 SuperSASS'], 'Active', 'Armalite AR-10', ARRAY['7.62 NATO', '.308 Win'], ARRAY['ar10', 'armalite ar10'], 'Cold War', 'Single-Action', ARRAY['military', 'hunting', 'competition'], 'Eugene Stoner designed the AR-10 before the AR-15; the AR-15 was a scaled-down AR-10 chambered in .223. The AR-10 is thus the grandfather of all modern AR-pattern rifles.', 'United States', true, 'Original Armalite AR-10s (1956-1960, made in Holland for Portugal/Sudan) are extremely rare and collectible.'),

('Armalite', 'AR-15', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 1964, false, 'United States', 'Armalite''s civilian version of the AR-15, the pattern that became the M16. The modern Armalite AR-15 is a mil-spec semi-automatic rifle.', 999, 128.0, 36.0, false, false, ARRAY['M15 Carbine', 'M15 Tactical'], 'Active', 'Armalite AR-15', ARRAY['5.56 NATO', '.223 Rem'], ARRAY['ar15', 'armalite ar-15', 'm15'], 'Cold War', 'Single-Action', ARRAY['sport', 'home defense'], NULL, 'United States', false, NULL),

('Armalite', 'M-15', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 1995, false, 'United States', 'Modern Armalite carbine-length AR-15 with M4-style features. The primary Armalite civilian AR offering in the post-AWB era.', 1099, 128.0, 32.0, false, false, ARRAY['M15 Competition', 'M15 Light Tactical'], 'Active', 'Armalite M-15', ARRAY['5.56 NATO'], ARRAY['m15', 'armalite m15'], 'Modern', 'Single-Action', ARRAY['sport', 'competition'], NULL, 'United States', false, NULL),

