('Armi Sport', 'Sharps 1874', '.45-70 Government', 'Rifle', 'Single-Action', 1, 1990, false, 'Italy', 'Reproduction of the Sharps Model 1874 falling-block single-shot rifle. Used in BPCR silhouette competition and by Civil War/Old West reenactors.', 1199, 128.0, 47.0, false, false, ARRAY['Business Rifle', 'Sporting Rifle', 'Long Range Express'], 'Active', 'Armi Sport Sharps', ARRAY['.45-70', '.45-90', '.40-65'], ARRAY['armi sport sharps', '1874 sharps reproduction'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['competition', 'collector'], NULL, 'Italy', false, NULL),

('Armi Sport', '1858 Remington', '.44 Caliber', 'Revolver', 'Single-Action', 6, 1985, false, 'Italy', 'Percussion reproduction of the 1858 Remington Army revolver. One of the most popular Civil War revolver reproductions due to the Remington''s modern feel and top-strap frame.', 299, 41.0, 13.5, false, false, ARRAY['Stainless', 'Target', 'Sheriff'], 'Active', 'Armi Sport 1858', ARRAY['.44 Caliber'], ARRAY['1858 remington repro', 'remington army reproduction'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['collector', 'competition'], NULL, 'Italy', false, NULL),

('Armi Sport', '1863 Springfield', '.58 Caliber', 'Rifle', 'Single-Action', 1, 1988, false, 'Italy', 'Percussion reproduction of the Model 1863 Springfield rifle-musket — the most common Union infantry rifle of the Civil War. Used extensively by reenactors and NSSA competition shooters.', 599, 128.0, 56.0, false, false, NULL, 'Active', 'Armi Sport Springfield', ARRAY['.58 Caliber'], ARRAY['springfield 1863', 'springfield musket reproduction'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['collector', 'competition'], NULL, 'Italy', false, NULL),

