-- ── ASTRA ────────────────────────────────────────────────────
('Astra', 'Model 400', '9mm Largo', 'Pistol', 'Semi-Auto', 8, 1921, true, 'Spain', 'Spanish military service pistol chambered in 9mm Largo. The standard Spanish Army sidearm from the 1920s through the early 1980s. Notable for its ability to safely fire multiple 9mm variants.', NULL, 35.3, 9.4, true, true, ARRAY['Model 400 in 9mm Parabellum', 'Model 400 in .38 ACP'], 'Discontinued', 'Astra 400', ARRAY['9mm Largo', '9mm Parabellum'], ARRAY['astra 400', 'modelo 400'], 'World War II', 'Single-Action', ARRAY['military', 'collector'], 'The Astra 400 was designed to chamber and fire seven different pistol cartridges due to its strong recoil spring — including 9mm Largo, 9mm Parabellum, 9mm Steyr, and .38 ACP. This interchangeability was a significant military advantage.', 'Spain', true, 'Spanish military issue examples with matching numbers are most collectible. WWII German-contract Astra 600 variants are especially sought.'),

('Astra', 'Model 600', '9mm Parabellum', 'Pistol', 'Semi-Auto', 8, 1943, true, 'Spain', 'Wartime production pistol made under German contract in 9mm Parabellum. A compact version of the 400 series made specifically for the Wehrmacht. Approximately 59,000 produced before the war ended.', NULL, 32.0, 8.1, true, false, NULL, 'Discontinued', 'Astra 600', ARRAY['9mm Parabellum'], ARRAY['astra 600', 'modelo 600'], 'World War II', 'Single-Action', ARRAY['military', 'collector'], 'The Astra 600 was ordered by Germany in 1943 but the war ended before full delivery could be made. Many undelivered pistols were subsequently sold to the Spanish police and exported.', 'Spain', true, 'German-contract 600s with German acceptance stamps command significant premiums.'),

('Astra', 'Constable', '.380 ACP', 'Pistol', 'DA/SA', 7, 1969, true, 'Spain', 'Modern double-action compact pistol from Astra chambered in .380 ACP. Sold widely in the US through the 1970s and 1980s as a concealed carry pistol. Clean design with Walther PP-inspired layout.', 250, 26.0, 6.5, false, false, ARRAY['Constable in .22 LR', 'Constable Sport'], 'Discontinued', 'Astra Constable', ARRAY['.380 ACP', '.22 LR'], ARRAY['constable', 'astra constable'], 'Cold War', 'DA/SA', ARRAY['carry', 'collector'], NULL, 'Spain', false, NULL),

