-- ── BLASER ───────────────────────────────────────────────────
('Blaser', 'R8', 'Various', 'Rifle', 'Bolt-Action', 3, 1998, false, 'Germany', 'Straight-pull bolt-action hunting rifle with a unique radial collet locking system and modular barrel/caliber exchange. The R8 can be switched between calibers in seconds without tools. Used by professional hunters worldwide.', 3995, 112.0, 40.0, false, false, ARRAY['R8 Professional Success', 'R8 Ultimate', 'R8 Safari'], 'Active', 'Blaser R8', ARRAY['Various', '.30-06', '9.3x62', '.300 Win Mag', '6.5 Creedmoor'], ARRAY['blaser r8', 'r8'], 'Modern', 'Single-Action', ARRAY['hunting', 'competition'], 'The Blaser R8 straight-pull bolt requires only about 50mm of bolt movement to cycle — roughly half that of a conventional turn-bolt. This dramatically increases follow-up shot speed.', 'Germany', false, NULL),

('Blaser', 'R93', 'Various', 'Rifle', 'Bolt-Action', 3, 1993, true, 'Germany', 'Predecessor to the R8 — the first commercially successful straight-pull bolt-action hunting rifle. The R93 established the Blaser approach of modular caliber exchange and fast-cycling straight-pull operation.', 2999, 108.0, 40.0, false, false, ARRAY['R93 Synthetic', 'R93 Professional', 'R93 LRS2 (long-range sniper)'], 'Discontinued', 'Blaser R93', ARRAY['Various'], ARRAY['blaser r93', 'r93'], 'Modern', 'Single-Action', ARRAY['hunting', 'competition'], 'The R93 LRS2 variant was used as a military sniper rifle by several nations, making the Blaser straight-pull one of the rare hunting-origin rifles to see genuine military service.', 'Germany', true, NULL),

('Blaser', 'F3', '12 Gauge', 'Shotgun', 'Break-Action', 2, 2005, false, 'Germany', 'Competition over-and-under shotgun from Blaser, offered in sporting, trap, and skeet configurations. Features an adjustable comb and Blaser''s signature aesthetic.', 4200, 108.0, 47.0, false, false, ARRAY['F3 Supersport', 'F3 Attache', 'F3 Game'], 'Active', 'Blaser F3', ARRAY['12 Gauge', '20 Gauge'], ARRAY['blaser f3', 'f3 shotgun'], 'Modern', 'Single-Action', ARRAY['competition', 'hunting'], NULL, 'Germany', false, NULL),

