('Bravo Company (BCM)', 'BCM4 RECCE-16', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 2004, false, 'United States', 'Mil-spec AR-15 carbine with a 16" mid-length gas system barrel. BCM''s flagship configuration, built to Crane Naval Surface Warfare Center specifications. The standard by which mil-spec AR-15s are judged.', 1299, 128.0, 32.5, false, true, ARRAY['RECCE-14', 'RECCE-11', 'RECCE-16 MCMR'], 'Active', 'BCM RECCE', ARRAY['5.56 NATO', '.223 Wylde'], ARRAY['bcm recce-16', 'bcm ar15', 'recce 16'], 'Modern', 'Single-Action', ARRAY['military', 'sport', 'home defense'], 'BCM is one of a small number of civilian AR-15 manufacturers that builds to Crane Naval Surface Warfare Center standards — the same spec document used for US SOCOM rifles.', 'United States', false, NULL),

('Bravo Company (BCM)', 'GUNFIGHTER Pistol', '5.56 NATO', 'Pistol', 'Semi-Auto', 30, 2012, false, 'United States', 'AR-15 pistol configuration with 9" or 11.5" barrel and pistol brace, built to BCM''s mil-spec standard. Compact PDW-style platform.', 1199, 96.0, 24.0, false, false, ARRAY['GUNFIGHTER 11.5"', 'GUNFIGHTER 9"'], 'Active', 'BCM GUNFIGHTER', ARRAY['5.56 NATO', '.300 BLK'], ARRAY['bcm pistol', 'bcm gunfighter'], 'Modern', 'Single-Action', ARRAY['sport', 'home defense'], NULL, 'United States', false, NULL),

('Bravo Company (BCM)', 'CQB', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 2006, false, 'United States', 'BCM close-quarters battle configuration with a 10.5" barrel, suppressor-optimized, and carbine gas system. Closest civilian equivalent to SOCOM CQB configuration.', 1349, 112.0, 26.5, false, false, NULL, 'Active', 'BCM CQB', ARRAY['5.56 NATO'], ARRAY['bcm cqb', 'bcm 10.5'], 'Modern', 'Single-Action', ARRAY['sport', 'home defense'], NULL, 'United States', false, NULL),

-- ── BUL ARMORY ────────────────────────────────────────────────
('Bul Armory', 'SAS II', '9mm Luger', 'Pistol', 'Single-Action', 17, 1998, false, 'Israel', 'Israeli polymer-frame double-stack 1911-style pistol. The SAS II combines the 1911''s single-action trigger with a modern polymer frame and higher capacity magazine. Manufactured in Israel and exported worldwide.', 799, 33.0, 8.5, false, false, ARRAY['SAS II Ultra', 'SAS II Compact', 'SAS II in .45 ACP'], 'Active', 'Bul SAS', ARRAY['9mm Luger', '.40 S&W', '.45 ACP'], ARRAY['bul sas ii', 'sas 2'], 'Modern', 'Single-Action', ARRAY['competition', 'carry'], 'Bul Armory''s double-stack polymer 1911 predates the widespread adoption of polymer-frame 1911s by American manufacturers by several years.', 'Israel', false, NULL),

('Bul Armory', 'Cherokee', '9mm Luger', 'Pistol', 'Single-Action', 15, 2005, false, 'Israel', 'Compact all-steel 1911-style pistol from Bul with a shorter grip and barrel. Aimed at the concealed carry market with traditional 1911 ergonomics in a more compact package.', 699, 28.0, 7.5, false, false, NULL, 'Active', 'Bul Cherokee', ARRAY['9mm Luger', '.40 S&W'], ARRAY['bul cherokee', 'cherokee 1911'], 'Modern', 'Single-Action', ARRAY['carry'], NULL, 'Israel', false, NULL),

('Bul Armory', 'M-5', '9mm Luger', 'Pistol', 'Single-Action', 17, 2010, false, 'Israel', 'Full-size competition-grade 1911 from Bul Armory with an extended barrel bushing, flared magwell, and match-grade barrel. Designed for IPSC/USPSA Limited and Open division competition.', 1299, 40.0, 8.9, false, false, ARRAY['M-5 Government', 'M-5 Transform'], 'Active', 'Bul M-5', ARRAY['9mm Luger', '.40 S&W', '.38 Super'], ARRAY['bul m5', 'm5 competition'], 'Modern', 'Single-Action', ARRAY['competition'], NULL, 'Israel', false, NULL),

-- ── BUSHMASTER ────────────────────────────────────────────────
('Bushmaster', 'XM15-E2S', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 1992, true, 'United States', 'Bushmaster''s flagship AR-15 carbine. One of the most widely sold AR-15s of the 1990s and 2000s. The XM15-E2S was a mil-spec carbine offered at competitive pricing.', 899, 128.0, 32.5, false, false, ARRAY['XM15 A2', 'XM15 M4 Patrolman'], 'Discontinued', 'Bushmaster XM15', ARRAY['5.56 NATO', '.223 Rem'], ARRAY['xm15', 'bushmaster ar15', 'xm15-e2s'], 'Modern', 'Single-Action', ARRAY['sport', 'home defense'], NULL, 'United States', false, NULL),

('Bushmaster', 'ACR', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 2009, true, 'United States', 'Adaptive Combat Rifle — a modular rifle originally developed by Magpul as the Masada concept. Features quick-change barrels, ambidextrous controls, and a folding stock. Originally promising but commercially unsuccessful at its price point.', 1999, 140.0, 36.0, false, false, ARRAY['ACR Enhanced', 'ACR Basic'], 'Discontinued', 'Bushmaster ACR', ARRAY['5.56 NATO', '.300 BLK', '6.8 SPC'], ARRAY['acr', 'bushmaster acr', 'masada'], 'Modern', 'Single-Action', ARRAY['sport', 'military'], 'The ACR (originally the Magpul Masada) was one of the most eagerly anticipated rifle designs of the 2000s. When it launched at $2,700 — nearly triple the rumored target price — it became one of the most disappointing commercial launches in modern firearms history.', 'United States', false, NULL),

('Bushmaster', 'Carbon 15', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 1993, true, 'United States', 'Ultra-lightweight AR-15 with a carbon fiber upper and lower receiver. The Carbon 15 weighed under 4 lbs — significantly lighter than any aluminum AR at the time.', 799, 56.0, 32.5, false, false, ARRAY['Carbon 15 Pistol', 'Carbon 15 Officer'], 'Discontinued', 'Bushmaster Carbon 15', ARRAY['5.56 NATO'], ARRAY['carbon 15', 'bushmaster carbon'], 'Modern', 'Single-Action', ARRAY['sport'], NULL, 'United States', false, NULL),

