('CVA', 'Optima V2', '.50 Caliber', 'Rifle', 'Single-Action', 1, 2009, false, 'United States', 'Inline muzzleloader with a break-action system for easy loading and cleaning. Reliable, affordable, and accurate. One of the best-selling hunting muzzleloaders in the US market.', 299, 64.0, 42.0, false, false, ARRAY['Optima V2 LR (long range)', 'Optima V2 Northwest'], 'Active', 'CVA Optima', ARRAY['.50 Caliber'], ARRAY['optima v2', 'cva optima'], 'Modern', 'Single-Action', ARRAY['hunting'], NULL, 'United States', false, NULL),

('CVA', 'Accura MR-X', '.50 Caliber', 'Rifle', 'Single-Action', 1, 2017, false, 'United States', 'Premium inline muzzleloader with a Nitride-finished Bergara barrel and a thumbhole stock. CVA''s top-of-line hunting muzzleloader offering sub-MOA accuracy capability.', 699, 72.0, 44.0, false, false, ARRAY['Accura MR (original)', 'Accura V2'], 'Active', 'CVA Accura', ARRAY['.50 Caliber'], ARRAY['accura mr-x', 'cva accura'], 'Modern', 'Single-Action', ARRAY['hunting', 'competition'], NULL, 'United States', false, NULL),

('CVA', 'Paramount', '.40 Caliber', 'Rifle', 'Single-Action', 1, 2019, false, 'United States', 'Long-range inline muzzleloader designed for 200-300 yard accuracy. Uses a proprietary PowerBelt ELR bullet system and is optimized for consistent long-range hunting performance.', 899, 80.0, 52.0, false, false, ARRAY['Paramount Pro', 'Paramount HTR'], 'Active', 'CVA Paramount', ARRAY['.40 Caliber', '.45 Caliber'], ARRAY['paramount', 'cva paramount'], 'Modern', 'Single-Action', ARRAY['hunting'], 'CVA Paramount created the "long-range muzzleloader" product category — no prior inline muzzleloader was specifically engineered for consistent accuracy at 300 yards.', 'United States', false, NULL),

-- ── CABOT GUNS ────────────────────────────────────────────────
('Cabot Guns', 'National Standard', '.45 ACP', 'Pistol', 'Single-Action', 8, 2011, false, 'United States', 'Cabot''s entry-level ultra-precision 1911. "Entry-level" here means $3,750 — every Cabot 1911 is machined from billet steel to tolerances measured in tenths of a thousandth of an inch.', 3750, 40.0, 8.75, false, false, NULL, 'Active', 'Cabot 1911', ARRAY['.45 ACP', '9mm Luger'], ARRAY['national standard', 'cabot 1911'], 'Modern', 'Single-Action', ARRAY['collector', 'competition'], 'Cabot''s manufacturing process uses aerospace-grade equipment to achieve 1911 fit tolerances that most shops consider impossible. Their slides fit frames with zero perceptible play — closer to a gauge block than a firearm.', 'United States', true, 'Cabot guns are among the most precisely manufactured production 1911s in existence. The One (a meteorite-steel 1911 sold at auction) sold for over $1,000,000.'),

('Cabot Guns', 'Jones', '.45 ACP', 'Pistol', 'Single-Action', 8, 2014, false, 'United States', 'Lightweight commander-size 1911 with carbon steel construction and Cabot''s full precision machining. The Jones is the Commander equivalent in the Cabot lineup.', 4250, 35.0, 8.0, false, false, NULL, 'Active', 'Cabot 1911', ARRAY['.45 ACP', '9mm Luger'], ARRAY['cabot jones', 'jones 1911'], 'Modern', 'Single-Action', ARRAY['carry', 'collector'], NULL, 'United States', true, NULL),

('Cabot Guns', 'American Joe', '.45 ACP', 'Pistol', 'Single-Action', 8, 2016, false, 'United States', 'Full-size 1911 with patriotic American theme — machined in the US from US-sourced steel. Cabot''s most decorated production model.', 4500, 40.0, 8.75, false, false, NULL, 'Active', 'Cabot 1911', ARRAY['.45 ACP'], ARRAY['american joe', 'cabot american'], 'Modern', 'Single-Action', ARRAY['collector'], NULL, 'United States', true, 'Limited production with documented serial numbers commands collector premium.'),

