('Cadex Defence', 'CDX-30', '.30 Caliber', 'Rifle', 'Bolt-Action', 5, 2012, false, 'Canada', 'Precision bolt-action chassis rifle from Canadian manufacturer Cadex. The CDX-30 uses a modular chassis system that accepts a wide range of stocks and configurations. Used by military snipers and competitive long-range shooters.', 3500, 176.0, 47.0, false, true, ARRAY['CDX-30 Lite', 'CDX-30 Evo', 'CDX-30 Kraken'], 'Active', 'Cadex CDX-30', ARRAY['.308 Win', '6.5 Creedmoor', '.300 Win Mag'], ARRAY['cdx30', 'cadex 30'], 'Modern', 'Single-Action', ARRAY['military', 'competition'], NULL, 'Canada', false, NULL),

('Cadex Defence', 'CDX-50 Tremor', '.50 BMG', 'Rifle', 'Bolt-Action', 5, 2015, false, 'Canada', 'Semi-bullpup anti-materiel precision rifle in .50 BMG. The CDX-50 has been adopted by several military and law enforcement agencies for long-range precision applications.', 9500, 320.0, 55.0, true, true, NULL, 'Active', 'Cadex CDX-50', ARRAY['.50 BMG'], ARRAY['cdx50 tremor', 'cadex 50 bmg'], 'Modern', 'Single-Action', ARRAY['military', 'competition'], NULL, 'Canada', false, NULL),

('Cadex Defence', 'CDX-40 Shadow', '.375 CheyTac', 'Rifle', 'Bolt-Action', 5, 2016, false, 'Canada', 'Extreme long-range bolt-action rifle chambered in .375 CheyTac and similar ELR cartridges. Built for sub-MOA accuracy at ranges beyond 2000 meters.', 7500, 256.0, 52.0, false, true, ARRAY['CDX-40 in .416 Barrett', 'CDX-40 in .408 CheyTac'], 'Active', 'Cadex CDX-40', ARRAY['.375 CheyTac', '.408 CheyTac'], ARRAY['cdx40 shadow', 'cadex shadow'], 'Modern', 'Single-Action', ARRAY['military', 'competition'], NULL, 'Canada', false, NULL),

