('Century Arms', 'VSKA', '7.62x39mm', 'Rifle', 'Semi-Auto', 30, 2019, false, 'United States', 'American-made AK-47 pattern rifle assembled by Century Arms with US-manufactured components. The VSKA uses a tool-steel bolt and US-made trunnion for improved durability over previous Century AK imports.', 699, 144.0, 36.6, false, false, ARRAY['VSKA Trooper', 'VSKA Magpul'], 'Active', 'Century VSKA', ARRAY['7.62x39mm'], ARRAY['vska', 'century ak', 'century arms ak47'], 'Modern', 'Single-Action', ARRAY['sport', 'home defense'], NULL, 'United States', false, NULL),

('Century Arms', 'WASR-10', '7.62x39mm', 'Rifle', 'Semi-Auto', 30, 2003, false, 'Romania', 'Romanian-manufactured AK-pattern semi-auto imported and refined by Century Arms. The WASR-10 is one of the most common and well-known AK imports in the US market. Later production WASR-10s improved significantly over early examples.', 699, 144.0, 36.5, false, false, ARRAY['WASR-10 V2', 'WASR-10 UF'], 'Active', 'Century WASR', ARRAY['7.62x39mm'], ARRAY['wasr10', 'wasr-10', 'century wasr'], 'Modern', 'Single-Action', ARRAY['sport', 'home defense'], 'Early WASR-10 imports had quality control issues with canted front sights and sloppy magazine fit. Post-2010 examples were significantly improved after Century tightened their QC processes.', 'Romania', false, NULL),

('Century Arms', 'C39v2', '7.62x39mm', 'Rifle', 'Semi-Auto', 30, 2016, true, 'United States', 'US-manufactured milled-receiver AK-pattern rifle. The C39v2 used a machined-from-solid US steel receiver — more expensive to produce but beloved by AK purists who prefer milled over stamped.', 899, 144.0, 36.5, false, false, NULL, 'Discontinued', 'Century C39', ARRAY['7.62x39mm'], ARRAY['c39v2', 'century c39', 'milled ak century'], 'Modern', 'Single-Action', ARRAY['sport'], NULL, 'United States', false, NULL),

