-- ── CHARTER ARMS ──────────────────────────────────────────────
('Charter Arms', 'Undercover', '.38 Special', 'Revolver', 'DA/SA Revolver', 5, 1964, false, 'United States', 'Lightweight 5-shot .38 Special revolver — one of the first snubnose revolvers designed specifically for concealed carry. The Undercover is significantly lighter than S&W J-frame equivalents due to an aluminum alloy frame.', 399, 16.0, 6.75, false, false, ARRAY['Undercover Lite', 'Undercover .32 H&R Mag'], 'Active', 'Charter Undercover', ARRAY['.38 Special', '.32 H&R Mag'], ARRAY['undercover', 'charter 38', 'charter arms undercover'], 'Cold War', 'DA/SA', ARRAY['carry'], 'An Undercover .38 Special was used by Squeaky Fromme in the 1975 assassination attempt on President Gerald Ford.', 'United States', false, NULL),

('Charter Arms', 'Bulldog', '.44 Special', 'Revolver', 'DA/SA Revolver', 5, 1973, false, 'United States', 'Compact 5-shot .44 Special revolver — one of the few production revolvers offering .44 Special in a concealable package. Popularized the concept of a large-caliber snubnose.', 399, 21.0, 7.0, false, false, ARRAY['Bulldog Pug', 'Bulldog Police', 'Bulldog .45 Colt'], 'Active', 'Charter Bulldog', ARRAY['.44 Special', '.45 Colt'], ARRAY['bulldog', 'charter bulldog', 'charter 44'], 'Cold War', 'DA/SA', ARRAY['carry'], 'The .44 Caliber Killer (Son of Sam) David Berkowitz used a Charter Arms Bulldog .44 Special in his 1976-1977 New York City murders. The notoriety drove massive public interest in the model.', 'United States', false, NULL),

('Charter Arms', 'Pitbull', '9mm Luger', 'Revolver', 'DA/SA Revolver', 5, 2012, false, 'United States', 'Rimless-cartridge revolver in 9mm Luger using Charter Arms''s proprietary spring-loaded extractor system — no moon clips required. One of the only production revolvers to chamber 9mm without moon clips.', 449, 22.0, 7.0, false, false, ARRAY['Pitbull .40 S&W', 'Pitbull .45 ACP'], 'Active', 'Charter Pitbull', ARRAY['9mm Luger', '.40 S&W', '.45 ACP'], ARRAY['pitbull', 'charter pitbull', 'charter 9mm revolver'], 'Modern', 'DA/SA', ARRAY['carry'], 'The Charter Arms Pitbull is one of only three production revolvers in history designed to fire rimless auto cartridges without moon clips — a genuinely unusual engineering achievement.', 'United States', false, NULL),

-- ── CHIAPPA FIREARMS ──────────────────────────────────────────
('Chiappa Firearms', 'Rhino', '.357 Magnum', 'Revolver', 'DA/SA Revolver', 6, 2009, false, 'Italy', 'Revolutionary revolver design by Emilio Ghisoni (also of Mateba) that fires from the bottom chamber of the cylinder rather than the top. This lowers the bore axis dramatically, reducing muzzle flip. Available in 2" to 6" barrels.', 999, 24.0, 7.0, false, false, ARRAY['Rhino 40DS (4")', 'Rhino 60DS (6")', 'Rhino 20DS (2")', 'Rhino in 9mm'], 'Active', 'Chiappa Rhino', ARRAY['.357 Magnum', '9mm Luger', '.40 S&W'], ARRAY['rhino', 'chiappa rhino'], 'Modern', 'DA/SA', ARRAY['carry', 'competition', 'collector'], 'Emilio Ghisoni patented the bottom-firing revolver concept with the Mateba Autorevolver in 1994 and refined it into the Rhino — the first commercially successful bottom-firing revolver.', 'Italy', false, NULL),

('Chiappa Firearms', 'Little Badger', '.22 LR', 'Rifle', 'Single-Action', 1, 2013, false, 'Italy', 'Ultra-compact single-shot folding rifle in .22 LR weighing just 2.9 lbs. The stock and barrel fold together for extreme portability. Popular as a survival/backpacking rifle.', 199, 46.4, 29.0, false, false, ARRAY['Little Badger in .22 Magnum', 'Little Badger in .17 HMR'], 'Active', 'Chiappa Little Badger', ARRAY['.22 LR', '.22 Magnum', '.17 HMR'], ARRAY['little badger', 'chiappa folding 22'], 'Modern', 'Single-Action', ARRAY['hunting', 'survival'], NULL, 'Italy', false, NULL),

('Chiappa Firearms', 'Triple Threat', '12 Gauge', 'Shotgun', 'Break-Action', 3, 2011, false, 'Italy', 'Triple-barrel break-action 12-gauge — one of the only production three-barrel shotguns available. Two side-by-side barrels plus a third under-barrel, all 18.5", with three independent triggers.', 1199, 144.0, 37.0, false, false, NULL, 'Active', 'Chiappa Triple Threat', ARRAY['12 Gauge'], ARRAY['triple threat', 'chiappa 3 barrel'], 'Modern', 'Single-Action', ARRAY['home defense', 'collector'], 'The Chiappa Triple Threat is one of only a handful of triple-barrel shotguns ever offered as a production firearm.', 'Italy', false, NULL),

