('Cimarron Firearms', 'Peacemaker SAA', '.357 Magnum', 'Revolver', 'Single-Action Revolver', 6, 1984, false, 'Italy', 'Faithful reproduction of the Colt Single Action Army revolver made by Uberti for Cimarron. The Peacemaker is Cimarron''s primary SAA reproduction, available in dozens of caliber and barrel configurations.', 549, 37.0, 11.0, false, false, ARRAY['Peacemaker in .45 Colt', 'Peacemaker in .44-40', 'Peacemaker Sheriff (3.5" barrel)'], 'Active', 'Cimarron SAA', ARRAY['.357 Magnum', '.45 Colt', '.44-40', '.44 Special'], ARRAY['peacemaker', 'cimarron saa', 'cimarron colt'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['collector', 'competition', 'hunting'], NULL, 'Italy', false, NULL),

('Cimarron Firearms', '1873 Winchester', '.45 Colt', 'Rifle', 'Lever-Action', 13, 1987, false, 'Italy', 'Reproduction of the Winchester Model 1873 lever-action rifle, made by Uberti for Cimarron. The most authentic and widely used Winchester 1873 replica available. Popular for Cowboy Action Shooting (SASS).', 1199, 128.0, 43.0, false, false, ARRAY['El Patron', 'Frontier 1873', 'Deluxe Engraved'], 'Active', 'Cimarron 1873', ARRAY['.45 Colt', '.44-40', '.357 Magnum', '.38 Special'], ARRAY['cimarron 1873', '1873 winchester reproduction'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['collector', 'competition'], NULL, 'Italy', false, NULL),

('Cimarron Firearms', 'Model P', '.45 Colt', 'Revolver', 'Single-Action Revolver', 6, 1984, false, 'Italy', 'Cimarron''s closest equivalent to a pre-war Colt SAA — the Model P uses period-correct dimensions and an action tuned to a light, crisp single-action pull. Often chosen over the standard Peacemaker by purists.', 599, 37.0, 11.0, false, false, ARRAY['Model P in .357 Mag', 'Model P New Sheriff (3.5")', 'Evil Roy (competition)'], 'Active', 'Cimarron Model P', ARRAY['.45 Colt', '.357 Magnum', '.44-40'], ARRAY['model p', 'cimarron model p'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['collector', 'competition'], NULL, 'Italy', false, NULL),

