('Daewoo Precision Industries', 'DP51', '9mm Luger', 'Pistol', 'DA/SA', 13, 1992, true, 'South Korea', 'Semi-automatic 9mm service pistol with Daewoo''s proprietary "Fast Action" trigger — a unique system where the hammer partially cocks on the rearward slide travel, resulting in a pull between SA and DA weight.', 499, 28.2, 7.5, false, true, ARRAY['DP51 Compact (DP52)', 'DP51C'], 'Discontinued', 'Daewoo DP', ARRAY['9mm Luger'], ARRAY['dp51', 'daewoo 9mm', 'dp-51'], 'Cold War', 'DA/SA', ARRAY['military', 'carry', 'collector'], 'The Daewoo DP51''s Fast Action trigger is found on no other production pistol. The partially-cocked hammer results in a consistent, moderate-weight trigger pull that experienced shooters compare favorably to a well-tuned SA.', 'South Korea', false, NULL),

('Daewoo Precision Industries', 'AR-100', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 1988, true, 'South Korea', 'South Korean AR-15 pattern semi-automatic rifle with a gas-piston operating system and a quick-change barrel feature. Imported to the US in limited quantities before import restrictions.', 699, 128.0, 39.5, false, false, NULL, 'Discontinued', 'Daewoo AR', ARRAY['5.56 NATO'], ARRAY['ar100', 'daewoo ar-100', 'max-ii'], 'Cold War', 'Single-Action', ARRAY['sport', 'collector'], NULL, 'South Korea', false, NULL),

