('Dan Wesson', '715', '.357 Magnum', 'Revolver', 'DA/SA Revolver', 6, 1984, false, 'United States', 'Dan Wesson''s signature interchangeable-barrel .357 Magnum revolver. The 715 features Dan Wesson''s unique barrel shroud and nut system, allowing barrel swaps without tools. Known for exceptional accuracy and a superb single-action trigger.', 1399, 40.0, 10.5, false, false, ARRAY['715 with 4" barrel', '715 with 8" barrel', '715 with 2.5" barrel'], 'Active', 'Dan Wesson 715', ARRAY['.357 Magnum'], ARRAY['715', 'dw 715', 'dan wesson 357'], 'Modern', 'DA/SA', ARRAY['competition', 'hunting', 'collector'], 'Dan Wesson revolvers pioneered the interchangeable barrel concept — a single-frame revolver with multiple barrel lengths sold as a system. The nut-and-shroud design allows a non-gunsmith to change barrels in under 5 minutes with a simple tool.', 'United States', false, NULL),

('Dan Wesson', 'Kodiak', '10mm Auto', 'Revolver', 'DA/SA Revolver', 6, 1990, true, 'United States', 'Large-frame revolver in 10mm Auto — one of the few production revolvers ever chambered for this cartridge. Used as a hunting revolver and by handgun metallic silhouette competitors.', 899, 56.0, 12.0, false, false, ARRAY['Kodiak in .445 SuperMag'], 'Discontinued', 'Dan Wesson Large Frame', ARRAY['10mm Auto', '.445 SuperMag'], ARRAY['kodiak', 'dan wesson 10mm'], 'Modern', 'DA/SA', ARRAY['hunting', 'competition', 'collector'], NULL, 'United States', true, NULL),

('Dan Wesson', 'Pointman Major', '10mm Auto', 'Pistol', 'Single-Action', 9, 2001, false, 'United States', '1911-pattern semi-automatic pistol in 10mm Auto. The Pointman Major was among the first high-quality production 1911s offered in 10mm. Dan Wesson is now a CZ subsidiary making premium 1911s and 1911-influenced pistols.', 1549, 40.0, 8.75, false, false, ARRAY['Pointman Major in .45 ACP', 'Pointman Carry'], 'Active', 'Dan Wesson Pointman', ARRAY['10mm Auto', '.45 ACP', '9mm Luger'], ARRAY['pointman major', 'dw 1911 10mm'], 'Modern', 'Single-Action', ARRAY['competition', 'hunting'], NULL, 'United States', false, NULL),

