('DS Arms', 'SA58', '.308 Winchester', 'Rifle', 'Semi-Auto', 20, 1996, false, 'United States', 'American-made FN FAL-pattern semi-automatic rifle produced by DS Arms using original FN tooling. Available in dozens of configurations. The definitive American FAL and regarded as the most faithful US-made FAL equivalent.', 1399, 204.0, 43.0, false, false, ARRAY['SA58 Para Tactical (folding stock)', 'SA58 Carbine (16")', 'SA58 Congo', 'SA58 OSW (8.5")'], 'Active', 'DS Arms SA58', ARRAY['.308 Win', '7.62 NATO'], ARRAY['sa58', 'dsarms fal', 'dsa fal'], 'Modern', 'Roller-Delayed Blowback', ARRAY['sport', 'military', 'competition'], 'DS Arms purchased original FN manufacturing tooling from Portugal — making the SA58 the only US-made FAL built on actual FN production equipment rather than reverse-engineered copies.', 'United States', false, NULL),

('DS Arms', 'ZM4', '5.56 NATO', 'Rifle', 'Semi-Auto', 30, 2005, false, 'United States', 'DS Arms AR-15/M4 pattern semi-automatic rifle. The ZM4 applies DS Arms'' precision manufacturing standards to the AR-15 platform.', 1099, 128.0, 32.5, false, false, ARRAY['ZM4 Carbine', 'ZM4 A1 SPR'], 'Active', 'DS Arms ZM4', ARRAY['5.56 NATO', '6.5 Grendel'], ARRAY['zm4', 'dsarms ar15'], 'Modern', 'Single-Action', ARRAY['sport'], NULL, 'United States', false, NULL),

