('EAA Corporation', 'Witness', '9mm Luger', 'Pistol', 'DA/SA', 16, 1991, false, 'Italy', 'Full-size CZ75-pattern DA/SA pistol from Tanfoglio, imported by EAA. The Witness is one of the most popular competition pistols in IPSC/USPSA due to its reliability and wide availability of aftermarket parts. Also available as the Witness Steel (all-steel) for competition divisions requiring it.', 499, 33.0, 8.1, false, false, ARRAY['Witness Steel', 'Witness Compact', 'Witness P Full Size', 'Witness Elite Match'], 'Active', 'EAA Witness', ARRAY['9mm Luger', '.40 S&W', '.45 ACP', '10mm Auto', '.38 Super'], ARRAY['witness', 'eaa witness', 'tanfoglio witness'], 'Modern', 'DA/SA', ARRAY['competition', 'carry', 'sport'], 'The EAA Witness in 10mm Auto is one of the most popular full-size 10mm pistols available — offering the full power of the cartridge in a double-stack format at an accessible price.', 'Italy', false, NULL),

('EAA Corporation', 'Windicator', '.357 Magnum', 'Revolver', 'DA/SA Revolver', 6, 1992, false, 'Germany', 'Double-action revolver manufactured by Weihrauch and imported by EAA. Available in .357 Magnum and .38 Special. Affordable European-made revolver with a solid reputation for reliability.', 329, 34.0, 9.0, false, false, ARRAY['Windicator in .38 Special', 'Windicator 2" (snub)'], 'Active', 'EAA Windicator', ARRAY['.357 Magnum', '.38 Special'], ARRAY['windicator', 'eaa windicator'], 'Modern', 'DA/SA', ARRAY['carry', 'sport'], NULL, 'Germany', false, NULL),

('EAA Corporation', 'MC312', '12 Gauge', 'Shotgun', 'Semi-Auto', 5, 2015, false, 'Turkey', 'Gas-operated semi-automatic 12-gauge shotgun from Turkey, imported by EAA. Available in sport and home defense configurations. Competes with Stoeger and GForce in the budget semi-auto shotgun segment.', 399, 96.0, 47.0, false, false, ARRAY['MC312 Sport', 'MC312 Slug'], 'Active', 'EAA MC312', ARRAY['12 Gauge'], ARRAY['mc312', 'eaa mc312'], 'Modern', 'Single-Action', ARRAY['hunting', 'home defense'], NULL, 'Turkey', false, NULL),

