('Euroarms', '1853 Enfield', '.577 Caliber', 'Rifle', 'Single-Action', 1, 1975, false, 'Italy', 'Percussion reproduction of the Pattern 1853 Enfield rifle-musket — the standard British military rifle of the Civil War era, widely used by both sides. Most common Civil War Enfield reproduction for reenactors and NSSA competition.', 499, 128.0, 55.0, false, false, NULL, 'Active', 'Euroarms Enfield', ARRAY['.577 Caliber'], ARRAY['1853 enfield', 'euroarms enfield', 'p53 enfield'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['collector', 'competition'], NULL, 'Italy', false, NULL),

('Euroarms', 'Rogers & Spencer', '.44 Caliber', 'Revolver', 'Single-Action Revolver', 6, 1972, false, 'Italy', 'Percussion reproduction of the Rogers & Spencer Army revolver — a Civil War-era US military revolver that was ordered but arrived after the war ended. Considered by many black powder shooters to be the finest-shooting of all Civil War revolver reproductions.', 349, 48.0, 13.75, false, false, ARRAY['Rogers & Spencer Target'], 'Active', 'Euroarms Rogers & Spencer', ARRAY['.44 Caliber'], ARRAY['rogers and spencer', 'r&s revolver'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['collector', 'competition'], 'The Rogers & Spencer was government-contracted but delivered after Appomattox. Had the war continued 90 more days, it would have been the Union Army''s standard revolver. Its design is considered superior to both the Colt and Remington it competed against.', 'Italy', false, NULL),

('Euroarms', '1861 Springfield', '.58 Caliber', 'Rifle', 'Single-Action', 1, 1978, false, 'Italy', 'Percussion reproduction of the Model 1861 Springfield rifle-musket. Along with the 1863, the most common Union infantry arm of the Civil War.', 549, 128.0, 56.0, false, false, NULL, 'Active', 'Euroarms Springfield', ARRAY['.58 Caliber'], ARRAY['1861 springfield', 'springfield musket repro'], 'Pre-WWI / Old West', 'Single-Action', ARRAY['collector', 'competition'], NULL, 'Italy', false, NULL)

